#include <bits/stdc++.h>
using namespace std;
int n,m,d,l,s[50004],ans,mark[50004];
int main(){
    cin>>n>>m>>d>>l;
    for(int i=1;i<=n;i++)cin>>s[i];
    sort(s+1,s+n+1);
    for(int i=1;i<=m;i++){
		int road=0;
		for(int i=1;i<=n;i++){
			if(!mark[i] && (s[i]-road*d>=l || (s[i]-road*d==0 && l==0))){
				road++;
				mark[i]=1;
			}
		}
		ans+=road;
    }
    cout<<ans;
    return 0;
}
